mapper.update:
UPDATE TBL_MTRL_M
SET PICKING_LOC_ID = #{pickingLocId},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{updtUser}
WHERE CMPY_CD = #{cmpyCd}
  AND MTRL_CD = #{mtrlCd}

    /* 1. 상품별 최적 로케이션(재고 有, BIN_NO 최소값)을 임시 테이블에 선정 */
    IF OBJECT_ID('tempdb..#BEST_LOC') IS NOT NULL DROP TABLE #BEST_LOC;

    SELECT
        S.CMPY_CD, S.AGNT_CD, S.MTRL_CD,
        L.LOC_ID,
        L.WH_CD
    INTO #BEST_LOC
    FROM TBL_STOCK S WITH(NOLOCK)
INNER JOIN TBL_WH_LOC_M L WITH(NOLOCK)
    ON S.CMPY_CD = L.CMPY_CD AND S.WH_CD = L.WH_CD AND S.LOC_ID = L.LOC_ID
    WHERE S.STOCK_QTY > 0
      AND S.CMPY_CD = #{cmpyCd}
      AND S.WH_CD = #{whCd}
      AND L.LOC_ID IN (
        SELECT TOP 1 T.LOC_ID
        FROM TBL_WH_LOC_M T
        INNER JOIN TBL_STOCK ST ON T.CMPY_CD = ST.CMPY_CD AND T.WH_CD = ST.WH_CD AND T.LOC_ID = ST.LOC_ID
        WHERE ST.MTRL_CD = S.MTRL_CD AND ST.AGNT_CD = S.AGNT_CD AND ST.STOCK_QTY > 0
        ORDER BY ISNULL(T.BIN_NO, 999) ASC, T.LEVEL_NO ASC, T.LOC_ID ASC
        );

    /* 2. 선정된 로케이션의 PICKING_YN을 'Y'로 승격 */
    UPDATE L
    SET L.PICKING_YN = 'Y',
        L.UPDT_TIME = GETDATE(),
        L.UPDT_USER = #{updtUser}
        FROM TBL_WH_LOC_M L
INNER JOIN #BEST_LOC B ON L.CMPY_CD = B.CMPY_CD AND L.WH_CD = B.WH_CD AND L.LOC_ID = B.LOC_ID;

    /* 3. 승격된 로케이션을 상품 마스터에 최종 지정 (1:1 매칭) */
    UPDATE M
    SET
        M.PICKING_LOC_ID = B.LOC_ID,
        M.UPDT_TIME = GETDATE(),
        M.UPDT_USER = #{updtUser}
        FROM TBL_MTRL_M M
INNER JOIN #BEST_LOC B ON M.CMPY_CD = B.CMPY_CD AND M.AGNT_CD = B.AGNT_CD AND M.MTRL_CD = B.MTRL_CD;

    DROP TABLE #BEST_LOC;

mapper.select:
SELECT TOP 1 LOC_ID
FROM TBL_WH_LOC_M WITH(NOLOCK)
WHERE CMPY_CD = #{cmpyCd}
  AND WH_CD = #{whCd}
  AND LOC_CD = #{locCd}
  AND USE_YN = 'Y'
  AND DELETED_YN = 'N'

mapper.update:
    /* 먼저 해당 로케이션을 피킹 가능 상태('Y')로 변경 */
    UPDATE TBL_WH_LOC_M
    SET PICKING_YN = 'Y',
        UPDT_TIME = GETDATE(),
        UPDT_USER = #{updtUser}
    WHERE CMPY_CD = #{cmpyCd}
      AND WH_CD = #{whCd}
      AND LOC_CD = #{locCd};

    /* 상품 마스터에 해당 로케이션 ID 반영 */
    UPDATE M
    SET M.PICKING_LOC_ID = L.LOC_ID,
        M.UPDT_TIME = GETDATE(),
        M.UPDT_USER = #{updtUser}
        FROM TBL_MTRL_M M
INNER JOIN TBL_WH_LOC_M L
    ON M.CMPY_CD = L.CMPY_CD AND L.WH_CD = #{whCd} AND L.LOC_CD = #{locCd}
    WHERE M.CMPY_CD = #{cmpyCd}
      AND M.AGNT_CD = #{agntCd}
      AND M.MTRL_CD = #{mtrlCd};
